#include <stdio.h>
#include <stdlib.h>

void generate_sequence(int n, int a, int b, int *sequence, int len) {
    if (len == (1 << n)) {
        for (int i = 0; i < len; i++) {
            printf("%d ", sequence[i]);
        }
        printf("\n");
        return;
    }
    for (int i = 0; i < (1 << n); i++) {
        if (i == a || i == b) continue;
        if (len > 0 && (sequence[len - 1] ^ i) != 1) continue;
        sequence[len] = i;
        generate_sequence(n, a, b, sequence, len + 1);
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, a, b;
        scanf("%d %d %d", &n, &a, &b);
        int *sequence = (int *)malloc((1 << n) * sizeof(int));
        generate_sequence(n, a, b, sequence, 0);
        free(sequence);
    }
    return 0;
}

