#include <iostream>
#include <vector>
using namespace std;

void generate_sequence(int n, int a, int b, vector<int> &sequence) {
    if (sequence.size() == (1 << n)) {
        for (int i = 0; i < sequence.size(); i++) {
            cout << sequence[i] << " ";
        }
        cout << endl;
        return;
    }
    for (int i = 0; i < (1 << n); i++) {
        if (i == a || i == b) continue;
        if (!sequence.empty() && (sequence.back() ^ i) != 1) continue;
        sequence.push_back(i);
        generate_sequence(n, a, b, sequence);
        sequence.pop_back();
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        int n, a, b;
        cin >> n >> a >> b;
        vector<int> sequence;
        generate_sequence(n, a, b, sequence);
    }
    return 0;
}

