import java.util.Scanner;

public class Main {
    public static void generate_sequence(int n, int a, int b, int[] sequence, int len) {
        if (len == (1 << n)) {
            for (int i = 0; i < len; i++) {
                System.out.print(sequence[i] + " ");
            }
            System.out.println();
            return;
        }
        for (int i = 0; i < (1 << n); i++) {
            if (i == a || i == b) continue;
            if (len > 0 && (sequence[len - 1] ^ i) != 1) continue;
            sequence[len] = i;
            generate_sequence(n, a, b, sequence, len + 1);
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            int a = scanner.nextInt();
            int b = scanner.nextInt();
            int[] sequence = new int[1 << n];
            generate_sequence(n, a, b, sequence, 0);
        }
    }
}

