import sys

def generate_sequence(n, a, b, sequence):
    if len(sequence) == (1 << n):
        print(' '.join(map(str, sequence)))
        return
    for i in range(1 << n):
        if i == a or i == b:
            continue
        if sequence and (sequence[-1] ^ i) != 1:
            continue
        sequence.append(i)
        generate_sequence(n, a, b, sequence)
        sequence.pop()

T = int(sys.stdin.readline())
for _ in range(T):
    n, a, b = map(int, sys.stdin.readline().split())
    sequence = []
    generate_sequence(n, a, b, sequence)

